#include <iostream>
#include <string>

int main() {
    Student s;
    std::cout << "Initial State:" << std::endl;
    std::cout << "Name: " << s.getName() << std::endl;
    std::cout << "ID: " << s.getId() << std::endl;
    std::cout << "Grade: " << s.getGrade() << std::endl;

    std::cout << "\nSetting values..." << std::endl;
    s.setName("Bob");
    s.setId(202);
    s.setGrade(88.8);

    std::cout << "Current State (after setGrade(88.8)): " << std::endl;
    std::cout << "Name: " << s.getName() << std::endl;
    std::cout << "ID: " << s.getId() << std::endl;
    std::cout << "Grade: " << s.getGrade() << std::endl;

    std::cout << "\nFurther check with s2:" << std::endl;
    Student s2;
    s2.setGrade(75.0);
    std::cout << "S2 ID after setGrade(75.0): " << s2.getId() << std::endl;
    std::cout << "S2 Grade after setGrade(75.0): " << s2.getGrade() << std::endl;

    return 0;
}
